import React from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { X, Trash2, ArrowRight } from 'lucide-react';
import { Link } from 'react-router-dom';
import { useCart } from '../context/CartContext';

const CartDrawer = () => {
    const { isCartOpen, closeCart, cartItems, removeFromCart, cartTotal } = useCart();

    return (
        <AnimatePresence>
            {isCartOpen && (
                <>
                    {/* Overlay */}
                    <motion.div
                        initial={{ opacity: 0 }}
                        animate={{ opacity: 0.5 }}
                        exit={{ opacity: 0 }}
                        onClick={closeCart}
                        style={{
                            position: 'fixed',
                            top: 0,
                            left: 0,
                            width: '100%',
                            height: '100%',
                            backgroundColor: 'black',
                            zIndex: 100
                        }}
                    />

                    {/* Drawer */}
                    <motion.div
                        initial={{ x: '100%' }}
                        animate={{ x: 0 }}
                        exit={{ x: '100%' }}
                        transition={{ type: 'tween', duration: 0.3 }}
                        style={{
                            position: 'fixed',
                            top: 0,
                            right: 0,
                            width: '100%',
                            maxWidth: '400px',
                            height: '100%',
                            backgroundColor: 'var(--color-surface)',
                            boxShadow: 'var(--shadow-premium)',
                            zIndex: 101,
                            display: 'flex',
                            flexDirection: 'column'
                        }}
                    >
                        {/* Header */}
                        <div style={{
                            padding: 'var(--spacing-lg)',
                            borderBottom: '1px solid var(--color-border)',
                            display: 'flex',
                            justifyContent: 'space-between',
                            alignItems: 'center'
                        }}>
                            <h2 style={{ fontSize: '1.25rem' }}>Shopping Cart</h2>
                            <button onClick={closeCart} style={{ color: 'var(--color-text-muted)' }}>
                                <X size={24} />
                            </button>
                        </div>

                        {/* Items */}
                        <div style={{ flex: 1, overflowY: 'auto', padding: 'var(--spacing-lg)' }}>
                            {cartItems.length === 0 ? (
                                <div style={{ textAlign: 'center', color: 'var(--color-text-muted)', marginTop: 'var(--spacing-3xl)' }}>
                                    <p>Your cart is empty.</p>
                                    <button
                                        onClick={closeCart}
                                        style={{
                                            marginTop: 'var(--spacing-md)',
                                            color: 'var(--color-accent)',
                                            fontWeight: 600,
                                            textDecoration: 'underline'
                                        }}
                                    >
                                        Continue Shopping
                                    </button>
                                </div>
                            ) : (
                                <ul style={{ display: 'flex', flexDirection: 'column', gap: 'var(--spacing-lg)' }}>
                                    {cartItems.map((item) => (
                                        <li key={item.id} style={{ display: 'flex', gap: 'var(--spacing-md)' }}>
                                            <div style={{ width: '80px', height: '80px', borderRadius: 'var(--radius-md)', overflow: 'hidden', flexShrink: 0 }}>
                                                <img src={item.images ? item.images[0] : item.image} alt={item.name} style={{ width: '100%', height: '100%', objectFit: 'cover' }} />
                                            </div>
                                            <div style={{ flex: 1 }}>
                                                <h3 style={{ fontSize: '1rem', fontWeight: 600 }}>{item.name}</h3>
                                                <p style={{ color: 'var(--color-text-muted)', fontSize: '0.9rem' }}>Qty: {item.quantity}</p>
                                                <p style={{ fontWeight: 600, color: 'var(--color-primary)' }}>${item.price * item.quantity}</p>
                                            </div>
                                            <button
                                                onClick={() => removeFromCart(item.id)}
                                                style={{ color: 'var(--color-error)', alignSelf: 'start' }}
                                            >
                                                <Trash2 size={18} />
                                            </button>
                                        </li>
                                    ))}
                                </ul>
                            )}
                        </div>

                        {/* Footer */}
                        {cartItems.length > 0 && (
                            <div style={{ padding: 'var(--spacing-lg)', borderTop: '1px solid var(--color-border)', backgroundColor: 'var(--color-background)' }}>
                                <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: 'var(--spacing-lg)', fontSize: '1.2rem', fontWeight: 700 }}>
                                    <span>Subtotal</span>
                                    <span>${cartTotal}</span>
                                </div>
                                <Link to="/checkout" onClick={closeCart} style={{ width: '100%' }}>
                                    <motion.button
                                        whileHover={{ scale: 1.02 }}
                                        whileTap={{ scale: 0.98 }}
                                        style={{
                                            width: '100%',
                                            padding: 'var(--spacing-md)',
                                            backgroundColor: 'var(--color-primary)',
                                            color: 'white',
                                            borderRadius: 'var(--radius-md)',
                                            fontSize: '1rem',
                                            fontWeight: 600,
                                            display: 'flex',
                                            alignItems: 'center',
                                            justifyContent: 'center',
                                            gap: 'var(--spacing-sm)'
                                        }}
                                    >
                                        Checkout <ArrowRight size={18} />
                                    </motion.button>
                                </Link>
                            </div>
                        )}
                    </motion.div>
                </>
            )}
        </AnimatePresence>
    );
};

export default CartDrawer;

import React, { useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { X, MessageCircle, Send } from 'lucide-react';

const ChatWidget = () => {
    const [isOpen, setIsOpen] = useState(false);
    const [messages, setMessages] = useState([
        { id: 1, text: 'Hello! How can we help you today?', sender: 'bot' }
    ]);
    const [inputValue, setInputValue] = useState('');

    const toggleChat = () => setIsOpen(!isOpen);

    const handleSendMessage = (e) => {
        e.preventDefault();
        if (!inputValue.trim()) return;

        const newMessage = { id: Date.now(), text: inputValue, sender: 'user' };
        setMessages([...messages, newMessage]);
        setInputValue('');

        // Simulate bot response
        setTimeout(() => {
            setMessages(prev => [...prev, {
                id: Date.now() + 1,
                text: "Thanks for reaching out! One of our style experts will be with you shortly.",
                sender: 'bot'
            }]);
        }, 1000);
    };

    return (
        <>
            <div style={{ position: 'fixed', bottom: 'var(--spacing-xl)', right: 'var(--spacing-xl)', zIndex: 100 }}>
                <AnimatePresence>
                    {isOpen && (
                        <motion.div
                            initial={{ opacity: 0, y: 20, scale: 0.9 }}
                            animate={{ opacity: 1, y: 0, scale: 1 }}
                            exit={{ opacity: 0, y: 20, scale: 0.9 }}
                            style={{
                                position: 'absolute',
                                bottom: '80px',
                                right: '0',
                                width: '350px',
                                height: '500px',
                                backgroundColor: 'var(--color-surface)',
                                borderRadius: 'var(--radius-lg)',
                                boxShadow: 'var(--shadow-premium)',
                                display: 'flex',
                                flexDirection: 'column',
                                overflow: 'hidden',
                                border: '1px solid var(--color-border)'
                            }}
                        >
                            {/* Header */}
                            <div style={{
                                padding: 'var(--spacing-md)',
                                backgroundColor: 'var(--color-primary)',
                                color: 'white',
                                display: 'flex',
                                justifyContent: 'space-between',
                                alignItems: 'center'
                            }}>
                                <div>
                                    <h4 style={{ margin: 0 }}>Support</h4>
                                    <span style={{ fontSize: '0.8rem', opacity: 0.8 }}>We reply immediately</span>
                                </div>
                                <button onClick={toggleChat} style={{ color: 'white' }}><X size={20} /></button>
                            </div>

                            {/* Messages */}
                            <div style={{
                                flex: 1,
                                padding: 'var(--spacing-md)',
                                overflowY: 'auto',
                                display: 'flex',
                                flexDirection: 'column',
                                gap: 'var(--spacing-md)'
                            }}>
                                {messages.map((msg) => (
                                    <div key={msg.id} style={{
                                        alignSelf: msg.sender === 'user' ? 'flex-end' : 'flex-start',
                                        backgroundColor: msg.sender === 'user' ? 'var(--color-accent)' : 'var(--color-background)',
                                        color: msg.sender === 'user' ? 'white' : 'var(--color-text-main)',
                                        padding: 'var(--spacing-sm) var(--spacing-md)',
                                        borderRadius: 'var(--radius-md)',
                                        maxWidth: '80%',
                                        boxShadow: 'var(--shadow-sm)'
                                    }}>
                                        {msg.text}
                                    </div>
                                ))}
                            </div>

                            {/* Input */}
                            <form onSubmit={handleSendMessage} style={{
                                padding: 'var(--spacing-md)',
                                borderTop: '1px solid var(--color-border)',
                                display: 'flex',
                                gap: 'var(--spacing-sm)'
                            }}>
                                <input
                                    type="text"
                                    value={inputValue}
                                    onChange={(e) => setInputValue(e.target.value)}
                                    placeholder="Type a message..."
                                    style={{
                                        flex: 1,
                                        padding: 'var(--spacing-sm)',
                                        borderRadius: 'var(--radius-md)',
                                        border: '1px solid var(--color-border)',
                                        outline: 'none'
                                    }}
                                />
                                <button type="submit" style={{
                                    padding: 'var(--spacing-sm)',
                                    backgroundColor: 'var(--color-accent)',
                                    color: 'white',
                                    borderRadius: 'var(--radius-md)'
                                }}>
                                    <Send size={20} />
                                </button>
                            </form>
                        </motion.div>
                    )}
                </AnimatePresence>

                <motion.button
                    onClick={toggleChat}
                    whileHover={{ scale: 1.1 }}
                    whileTap={{ scale: 0.9 }}
                    style={{
                        width: '60px',
                        height: '60px',
                        borderRadius: '50%',
                        backgroundColor: 'var(--color-accent)',
                        color: 'white',
                        display: 'flex',
                        alignItems: 'center',
                        justifyContent: 'center',
                        boxShadow: 'var(--shadow-lg)'
                    }}
                >
                    <MessageCircle size={30} />
                </motion.button>
            </div>
        </>
    );
};

export default ChatWidget;

import React from 'react';

class ErrorBoundary extends React.Component {
    constructor(props) {
        super(props);
        this.state = { hasError: false, error: null, errorInfo: null };
    }

    static getDerivedStateFromError(error) {
        return { hasError: true };
    }

    componentDidCatch(error, errorInfo) {
        this.setState({ error, errorInfo });
        console.error("Uncaught error:", error, errorInfo);
    }

    render() {
        if (this.state.hasError) {
            return (
                <div style={{ padding: '2rem', color: 'red' }}>
                    <h1>Something went wrong.</h1>
                    <details style={{ whiteSpace: 'pre-wrap' }}>
                        {this.state.error && this.state.error.toString()}
                        <br />
                        {this.state.errorInfo && this.state.errorInfo.componentStack}
                    </details>
                </div>
            );
        }

        return this.props.children;
    }
}

export default ErrorBoundary;

import React, { useState } from 'react';
import { Link } from 'react-router-dom';
import { ShoppingCart, Search, Menu, User, Sun, Moon, X } from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';

import { useCart } from '../context/CartContext';
import { useTheme } from '../context/ThemeContext';

const Header = () => {
  const { cartCount, openCart } = useCart();
  const { isDark, toggleTheme } = useTheme();
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);

  return (
    <header style={{
      position: 'sticky',
      top: 0,
      zIndex: 50,
      backgroundColor: 'var(--color-background)',
      backdropFilter: 'blur(12px)',
      borderBottom: '1px solid var(--color-border)',
      padding: 'var(--spacing-md) var(--spacing-xl)',
      transition: 'background-color 0.3s ease'
    }}>
      <div style={{
        maxWidth: '1200px',
        margin: '0 auto',
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'space-between'
      }}>
        {/* Logo */}
        <Link to="/" style={{
          fontFamily: 'var(--font-family-display)',
          fontSize: '1.8rem',
          fontWeight: 800,
          color: 'var(--color-text-main)',
          display: 'flex',
          alignItems: 'center',
          gap: 'var(--spacing-xs)',
          letterSpacing: '-1px',
          textDecoration: 'none'
        }}>
          ASTRA
        </Link>

        {/* Desktop Navigation */}
        <div className="desktop-nav" style={{ display: 'none', gap: 'var(--spacing-xl)', alignItems: 'center' }}>
          <Link to="/" className="nav-link">Home</Link>
          <Link to="/shop" className="nav-link">Shop</Link>
          <Link to="/sell" className="nav-link">Sell</Link>
          <Link to="/product/1" className="nav-link">Product</Link>
        </div>

        {/* Icons */}
        <div style={{ display: 'flex', alignItems: 'center', gap: 'var(--spacing-lg)' }}>
          {/* Theme Toggle */}
          <motion.button
            onClick={toggleTheme}
            whileHover={{ scale: 1.1 }}
            style={{ color: 'var(--color-text-main)', background: 'none', border: 'none', cursor: 'pointer' }}
          >
            {isDark ? <Sun size={20} /> : <Moon size={20} />}
          </motion.button>

          <motion.button whileHover={{ scale: 1.1 }} style={{ background: 'none', border: 'none', cursor: 'pointer' }}>
            <Search size={22} color="var(--color-text-main)" />
          </motion.button>

          <Link to="/login">
            <motion.button whileHover={{ scale: 1.1 }} style={{ background: 'none', border: 'none', cursor: 'pointer' }}>
              <User size={22} color="var(--color-text-main)" />
            </motion.button>
          </Link>

          <motion.div
            onClick={openCart}
            style={{ position: 'relative', cursor: 'pointer' }}
            whileHover={{ scale: 1.1 }}
          >
            <ShoppingCart size={22} color="var(--color-text-main)" />
            <span style={{
              position: 'absolute',
              top: '-8px',
              right: '-8px',
              backgroundColor: 'var(--color-accent)',
              color: 'white',
              fontSize: '0.7rem',
              fontWeight: 'bold',
              height: '18px',
              width: '18px',
              borderRadius: '50%',
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center'
            }}>{cartCount}</span>
          </motion.div>

          <button
            className="mobile-menu-btn"
            onClick={() => setIsMobileMenuOpen(true)}
            style={{ display: 'none', color: 'var(--color-text-main)', background: 'none', border: 'none', cursor: 'pointer' }}
          >
            <Menu size={24} />
          </button>
        </div>
      </div>

      {/* Mobile Menu Overlay */}
      <AnimatePresence>
        {isMobileMenuOpen && (
          <motion.div
            initial={{ opacity: 0, x: '100%' }}
            animate={{ opacity: 1, x: 0 }}
            exit={{ opacity: 0, x: '100%' }}
            transition={{ type: 'tween' }}
            style={{
              position: 'fixed',
              top: 0,
              right: 0,
              width: '100%',
              height: '100vh',
              backgroundColor: 'var(--color-background)',
              zIndex: 100,
              padding: 'var(--spacing-xl)',
              display: 'flex',
              flexDirection: 'column'
            }}
          >
            <div style={{ display: 'flex', justifyContent: 'flex-end', marginBottom: 'var(--spacing-2xl)' }}>
              <button onClick={() => setIsMobileMenuOpen(false)} style={{ background: 'none', border: 'none', cursor: 'pointer', color: 'var(--color-text-main)' }}>
                <X size={32} />
              </button>
            </div>
            <nav style={{ display: 'flex', flexDirection: 'column', gap: 'var(--spacing-xl)', fontSize: '1.5rem', fontWeight: 600 }}>
              <Link to="/" onClick={() => setIsMobileMenuOpen(false)} style={{ color: 'var(--color-text-main)', textDecoration: 'none' }}>Home</Link>
              <Link to="/shop" onClick={() => setIsMobileMenuOpen(false)} style={{ color: 'var(--color-text-main)', textDecoration: 'none' }}>Shop</Link>
              <Link to="/sell" onClick={() => setIsMobileMenuOpen(false)} style={{ color: 'var(--color-text-main)', textDecoration: 'none' }}>Sell</Link>
              <Link to="/login" onClick={() => setIsMobileMenuOpen(false)} style={{ color: 'var(--color-text-main)', textDecoration: 'none' }}>Login</Link>
            </nav>
          </motion.div>
        )}
      </AnimatePresence>

      <style>{`
        .nav-link {
          font-weight: 500;
          color: var(--color-text-muted);
          text-decoration: none;
          transition: var(--transition-normal);
        }
        .nav-link:hover {
          color: var(--color-accent);
        }
        @media (min-width: 769px) {
            .desktop-nav { display: flex !important; }
            .mobile-menu-btn { display: none !important; }
        }
        @media (max-width: 768px) {
            .desktop-nav { display: none !important; }
            .mobile-menu-btn { display: block !important; }
        }
      `}</style>
    </header>
  );
};

export default Header;

