                            required
                            style={{
                                width: '100%',
                                padding: '14px 14px 14px 48px',
                                borderRadius: '12px',
                                border: '1px solid var(--color-border)',
                                backgroundColor: 'var(--color-background)',
                                color: 'var(--color-text-main)',
                                outline: 'none',
                                fontFamily: 'inherit',
                                fontSize: '1rem',
                                transition: 'all 0.2s'
                            }}
                        />
                    </div>

                    <button
                        disabled={isSubmitting}
                        style={{
                            width: '100%',
                            padding: '14px',
                            backgroundColor: 'var(--color-primary)',
